const items = $input.all();

if (!items.length) {
  return [{ json: { startNewConversation: true } }];
}

items.sort((a, b) =>
  new Date(a.json.createdAt) - new Date(b.json.createdAt)
);

const lastItem = items[items.length - 1];

if (!lastItem.json.createdAt) {
  return [{ json: { startNewConversation: true } }];
}

const lastDate = new Date(lastItem.json.createdAt);
const now = new Date();

const diffMs = now - lastDate;

const startNewConversation = diffMs > 4 * 60 * 60 * 1000;

return [
  {
    json: {
      startNewConversation,
    },
  },
];

const items = $input.all();

for (const item of items) {
  const parsed = JSON.parse(item.json.output);

  item.json = {
    ...item.json,
    ...parsed,
  };
}

return items;

const items = $input.all();
const output = [];

for (const item of items) {
  const payload = item.json.content?.payload || {};

  for (const [key, value] of Object.entries(payload)) {
    output.push({
      json: {
        key,
        value,
      },
    });
  }
}

return output;

const items = $input.all();

const STATUS_LABEL = {
  1: 'Aberta',
  2: 'Em andamento',
  3: 'Concluída',
  4: 'Cancelada',
};

function formatDate(dateString) {
  if (!dateString) return '-';

  const date = new Date(dateString);

  if (isNaN(date)) return dateString;

  return date.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

const orders = items[0].json.data || [];

if (!orders.length) {
  return [
    {
      json: {
        message:
          'Não encontrei nenhuma ordem de serviço. Como posso te ajudar?',
      },
    },
  ];
}

let message = '*Suas ordens de serviço*\n\n';

for (const order of orders) {
  const statusTraduzido =
    STATUS_LABEL[order.status] ?? order.status ?? '-';

  const dataFormatada = formatDate(order.createdAt);

  message +=
    '━━━━━━━━━━━━━━━\n' +
    `🔢 Número: #${order.number ?? '-'}\n` +
    `📌 Situação: ${statusTraduzido}\n` +
    `👤 Cliente: ${order.client ?? '-'}\n` +
    `🚗 Veículo: ${order.vehicle ?? '-'}\n` +
    `🛠️ Serviço: ${order.description ?? '-'}\n` +
    `📅 Criada em: ${dataFormatada}\n`;
}

message += '━━━━━━━━━━━━━━━';

return [
  {
    json: {
      message,
      total: orders.length,
    },
  },
];
